PREFIX up: <http://purl.uniprot.org/core/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX GO: <http://purl.obolibrary.org/obo/GO_>
PREFIX : <http://purl.orthodb.org/>
PREFIX ip_highest: <http://string-db.org/rdf/interaction/physical-highest-confidence-cutoff>

SELECT ?gene_m ?gene_m_name ?partner_m ?string_partner_genename ?level ?percent_single_copy
WHERE {
    ?gene_m a :Gene .
    ?gene_m up:organism/a [up:scientificName "Mus musculus"] .
    ?gene_m :name ?gene_m_name .
    ?gene_m :memberOf ?og .
    ?og a :OrthoGroup ;
        :name ?og_description ;
        :ogBuiltAt [up:scientificName "Mammalia"] .
    ?og :xref [a :Xref; :xrefResource GO:0005164], [a :Xref; :xrefResource GO:0045739] .
    ?gene_m :xref [a :Xref; :xrefResource ?xref_m] .
    ?xref_m a :Entrezgene.

    SERVICE <https://sparql.string-db.org/sparql> {
        ?string_gene_m rdfs:seeAlso ?xref_m ;
            ip_highest: ?partner_m .
        ?partner_m rdfs:label ?string_partner_genename ;
            rdfs:comment ?string_partner_description .
    }

    ?gene_m2 a :Gene ;
        up:organism/a [up:scientificName "Mus musculus"] ;
        :name ?string_partner_genename ;
        :memberOf ?og2 .
    ?og2 a :OrthoGroup ;
        :ogBuiltAt/up:scientificName ?level ;
        :ogPercentSingleCopy ?percent_single_copy .
}

PREFIX up: <http://purl.uniprot.org/core/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX GO: <http://purl.obolibrary.org/obo/GO_>
PREFIX : <http://purl.orthodb.org/>
PREFIX np: <http://nextprot.org/rdf#>
PREFIX interpro: <http://www.ebi.ac.uk/interpro/entry/>

SELECT ?gene_zf ?gene_zf_name ?gene ?gene_name ?description ?go ?disease
WHERE {
	SERVICE <https://sparql.nextprot.org/> {
        select distinct ?entry ?disease WHERE {
            ?entry np:isoform / np:disease / rdfs:comment ?disease
        }
    }
    ?gene rdfs:seeAlso ?entry;
        :name ?gene_name ;
        :description ?description.
    ?gene :memberOf ?og .
    ?og :xref/:xrefResource interpro:IPR000719 , GO:0048013.
    ?og :ogBuiltAt/up:scientificName "Vertebrata";
        :hasMember ?gene_zf.
    ?gene_zf :name ?gene_zf_name;
        up:organism/a [up:scientificName "Danio rerio"].
} ORDER BY ?disease

PREFIX up: <http://purl.uniprot.org/core/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX : <http://purl.orthodb.org/>
PREFIX rh: <http://rdf.rhea-db.org/>
PREFIX interpro: <http://www.ebi.ac.uk/interpro/entry/>

SELECT ?og ?equation
    (group_concat (distinct ?clade_name; SEPARATOR="; ") as ?clades)
    (count(distinct ?taxon) as ?cnt_taxons)
    (count(distinct ?gene) as ?cnt_genes)
    (group_concat (distinct ?org_name; SEPARATOR="; ") as ?taxons)
WHERE {
    ?taxon a :Species; up:scientificName ?org_name ;
        rdfs:subClassOf+/up:scientificName ?clade_name.
    ?gene a :Gene ;
        up:organism/a ?taxon.
    ?gene rdfs:seeAlso ?xref.
    ?xref a :Uniprot.
    ?gene :memberOf ?og.
    ?og :xref/:xrefResource interpro:IPR002328 ;
        :ogBuiltAt/up:scientificName "Eukaryota".

    # join via uniprot ?xref
    SERVICE <https://sparql.uniprot.org/sparql> {
        ?xref a up:Protein ;
            up:annotation/up:catalyticActivity/up:catalyzedReaction ?rh .
    }

    # join via reaction ?rh
    SERVICE <https://sparql.rhea-db.org/sparql> {
        ?rh rdfs:subClassOf rh:Reaction ;
            rh:equation ?equation.
    }

    # restrict taxons to several clades
    VALUES ?clade_name {
        "Stramenopiles"
        "Alveolata"
        "Liliopsida"
        "Coleoptera"
    }
} GROUP BY ?equation ?og ORDER BY ?og ?equation

https://sparql.uniprot.org/.well-known/s.query:
PREFIX up:<http://purl.uniprot.org/core/>
PREFIX taxon:<http://purl.uniprot.org/taxonomy/>
PREFIX rdfs:<http://www.w3.org/2000/01/rdf-schema#>
PREFIX orth:<http://purl.org/net/orth#>
PREFIX dcterms:<http://purl.org/dc/terms/>
PREFIX obo:<http://purl.obolibrary.org/obo/>
PREFIX lscr:<http://purl.org/lscr#>
PREFIX genex:<http://purl.org/genex#>
PREFIX sio: <http://semanticscience.org/resource/>
SELECT ?gene ?orthologous_protein2 WHERE {
  {
    SELECT ?protein1 WHERE {
      ?protein1 a up:Protein;
        up:organism/up:scientificName 'Homo sapiens' ;
        up:annotation ?annotation .
      ?annotation rdfs:comment ?annotation_text.
      ?annotation a up:Disease_Annotation .
      FILTER CONTAINS (?annotation_text, "cancer")
    }
  }
  SERVICE <https://sparql.omabrowser.org/sparql/> {
    SELECT ?orthologous_protein2 ?protein1 ?gene WHERE {
      ?protein_OMA a orth:Protein .
      ?orthologous_protein2 a orth:Protein .
      ?cluster a orth:OrthologsCluster .
      ?cluster orth:hasHomologousMember ?node1 .
      ?cluster orth:hasHomologousMember ?node2 .
      ?node2 orth:hasHomologousMember* ?protein_OMA .
      ?node1 orth:hasHomologousMember* ?orthologous_protein2 
      .?orthologous_protein2 orth:organism/obo:RO_0002162/up:scientificName 'Rattus norvegicus' .
      ?orthologous_protein2 sio:SIO_010079 ?gene .
      ?protein_OMA lscr:xrefUniprot ?protein1 .
      FILTER(?node1 != ?node2)
    }
  }
  SERVICE <https://www.bgee.org/sparql/> {
    ?gene genex:isExpressedIn ?anatEntity .
    ?anatEntity rdfs:label 'brain' .
    ?gene orth:organism ?org . 
    ?org obo:RO_0002162 taxon:10116 .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX orth: <http://purl.org/net/orth#>
PREFIX sio: <http://semanticscience.org/resource/>
PREFIX taxon: <http://purl.uniprot.org/taxonomy/>
PREFIX up: <http://purl.uniprot.org/core/>
PREFIX lscr: <http://purl.org/lscr#>
PREFIX genex: <http://purl.org/genex#>
SELECT DISTINCT ?protein ?orthologous_protein ?gene ?annotation_text WHERE {
  {
  	SELECT ?protein ?annotation_text WHERE {
      ?protein a up:Protein ;
          up:organism taxon:9606 ;
          up:annotation ?annotation .
      ?annotation rdfs:comment ?annotation_text .
      ?annotation a up:Disease_Annotation .
      FILTER CONTAINS (?annotation_text, "glioblastoma")
    }
  }
  SERVICE <https://sparql.omabrowser.org/sparql/> {
    SELECT ?orthologous_protein ?protein ?gene WHERE {
    ?protein_OMA a orth:Protein .
    ?orthologous_protein a orth:Protein .
    ?cluster a orth:OrthologsCluster .
    ?cluster orth:hasHomologousMember ?node1 .
    ?cluster
    orth:hasHomologousMember ?node2 .
    ?node2 orth:hasHomologousMember* ?protein_OMA .
    ?node1 orth:hasHomologousMember* ?orthologous_protein .
    ?orthologous_protein orth:organism/obo:RO_0002162 taxon:10116 . # rattus norvegicus
    ?orthologous_protein sio:SIO_010079 ?gene .
    ?protein_OMA lscr:xrefUniprot ?protein .
    FILTER(?node1 != ?node2)
		}
	}
  SERVICE <https://www.bgee.org/sparql/> {
    ?gene genex:isExpressedIn ?a .
    ?a rdfs:label "brain" .
    ?gene orth:organism ?s . 
    ?s obo:RO_0002162 taxon:10116.
	}
}

https://sparql.rhea-db.org/.well-known/s.query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rh:<http://rdf.rhea-db.org/>
PREFIX CHEBI:<http://purl.obolibrary.org/obo/CHEBI_>
PREFIX ec:<http://purl.uniprot.org/enzyme/>
PREFIX up:<http://purl.uniprot.org/core/>
PREFIX taxon:<http://purl.uniprot.org/taxonomy/>
PREFIX keywords:<http://purl.uniprot.org/keywords/>

SELECT
  ?protein
  ?ecNumber
  ?reaction
WHERE {
  ?reaction rdfs:subClassOf rh:Reaction .
  ?reaction rh:status rh:Approved .
  ?reaction rh:ec ?ecNumber .
  ?reaction rh:side ?reactionSide .
  ?reactionSide rh:contains ?participant .
  ?participant rh:compound ?compound .
  ?compound rh:chebi ?chebi .

  SERVICE <https://sparql.uniprot.org/sparql> {
    ?protein a up:Protein ;
    up:reviewed true ;
    up:organism taxon:9606 ;
    {
      ?protein up:enzyme ?ecNumber
    } UNION {
      ?protein up:domain/up:enzyme ?ecNumber
    } UNION {
      ?protein up:component/up:enzyme ?ecNumber
    } .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rh: <http://rdf.rhea-db.org/>
PREFIX sachem: <http://bioinfo.uochb.cas.cz/rdf/v1.0/sachem#>


SELECT 
  ?rhea 
  ?chebi
WHERE {
  SERVICE <https://idsm.elixir-czech.cz/sparql/endpoint/chebi> {
    ?chebi sachem:substructureSearch [
        sachem:query "[C@]12(CCC3CCCC[C@]3(C)[C@@]1([H])CC[C@]1(C)[C@@]([H])([C@@](C)([H])CCCC(C)C)CC[C@@]21[H])[H]" ].
  }
  ?rhea rh:side/rh:contains/rh:compound/rdfs:subClassOf ?chebi .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX up: <http://purl.uniprot.org/core/>
PREFIX : <http://purl.orthodb.org/>
PREFIX rh:<http://rdf.rhea-db.org/>
PREFIX odbgroup:<http://purl.orthodb.org/odbgroup/>
SELECT *
WHERE {
  SERVICE <https://sparql.orthodb.org/sparql/> {
    ?gene a :Gene; :memberOf odbgroup:2906at28890.
    ?gene :xref [a :Xref; :xrefResource ?xref].
    ?xref a :Uniprot.
  }
  SERVICE <https://sparql.uniprot.org/sparql> {
    ?xref a up:Protein; up:recommendedName [up:fullName ?name] ;
    up:annotation/up:catalyticActivity/up:catalyzedReaction ?reaction .
  }
  ?reaction rdfs:subClassOf rh:Reaction .
  ?reaction rh:directionalReaction ?directionalReaction .
  OPTIONAL { ?directionalReaction rdfs:seeAlso ?xref2 . }
  ?reaction rh:bidirectionalReaction ?bidirectionalReaction .
  OPTIONAL { ?bidirectionalReaction rdfs:seeAlso ?xref2 . }
}

PREFIX chebislash: <http://purl.obolibrary.org/obo/chebi/>
PREFIX rh: <http://rdf.rhea-db.org/>
PREFIX taxon: <http://purl.uniprot.org/taxonomy/>
